const PROCESSING_FEE = 5;
const ITEM_BASE_PRICE = 100;

type Item = { type: string };
type QuoteStep = { op: "quote"; items: Item[] };
type Step = QuoteStep;
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

const quotePremium = (items: Item[]): number =>
  items.length * ITEM_BASE_PRICE + PROCESSING_FEE;

export const processScenario = (input: Scenario): unknown => {
  const results = input.steps.map((step) => ({
    premium: quotePremium(step.items),
  }));
  return { results };
};
